import { betterAuth } from "better-auth";
import { genericOAuth } from "better-auth/plugins";

const parseCsv = (value: string | undefined) =>
  value
    ?.split(",")
    .map((origin) => origin.trim())
    .filter(Boolean) ?? [];

export const auth = betterAuth({
  appName: "Krakstack Site",
  trustedOrigins: parseCsv(process.env.BETTER_AUTH_TRUSTED_ORIGINS),
  advanced: {
    cookiePrefix: "krakstack-site",
  },
  account: {
    encryptOAuthTokens: true,
    storeStateStrategy: "cookie",
    storeAccountCookie: true,
  },
  session: {
    cookieCache: {
      enabled: true,
      maxAge: 60 * 60 * 24 * 7,
      strategy: "jwe",
      refreshCache: true,
    },
  },
  plugins: [
    genericOAuth({
      config: [
        {
          providerId: "krakstack-auth",
          clientId: process.env.KRAKSTACK_AUTH_CLIENT_ID!,
          clientSecret: process.env.KRAKSTACK_AUTH_CLIENT_SECRET!,
          discoveryUrl:
            process.env.KRAKSTACK_AUTH_URL +
            "/.well-known/openid-configuration",
          redirectURI:
            process.env.BETTER_AUTH_URL + "/api/auth/callback/krakstack-auth",
          scopes: ["openid", "profile", "email"],
          pkce: true,
        },
      ],
    }),
  ],
});

export type AuthSession = typeof auth.$Infer.Session;

import { createAuthClient } from "better-auth/react";
import { genericOAuthClient } from "better-auth/client/plugins";

export const authClient = createAuthClient({
  plugins: [genericOAuthClient()],
});

import { apiKeyClient } from "@better-auth/api-key/client";
import { createAuthClient } from "better-auth/react";
import { twoFactorClient } from "better-auth/client/plugins";

export const centralAuthClient = createAuthClient({
  baseURL: import.meta.env.VITE_KRAKSTACK_AUTH_URL,
  fetchOptions: {
    credentials: "include",
  },
  plugins: [
    twoFactorClient({
      onTwoFactorRedirect: () => {
        window.location.href = `${import.meta.env.VITE_KRAKSTACK_AUTH_URL}/2fa`;
      },
    }),
    apiKeyClient(),
  ],
});

import { auth } from "@/services/auth/config";
import { createFileRoute } from "@tanstack/react-router";

export const Route = createFileRoute("/api/auth/$")({
  server: {
    handlers: {
      GET: async ({ request }: { request: Request }) => {
        return await auth.handler(request);
      },
      POST: async ({ request }: { request: Request }) => {
        return await auth.handler(request);
      },
    },
  },
});

import { Context, Effect, Layer } from "effect";
import { HttpServerRequest } from "effect/unstable/http";
import { HttpApiError } from "effect/unstable/httpapi";

import { auth } from "@/services/auth/config";

const internalServerError = () => new HttpApiError.InternalServerError({});

export class Auth extends Context.Service<Auth>()("Auth", {
  make: Effect.gen(function* () {
    const getSession = Effect.fn("Auth.getSession")(function* () {
      const request = yield* HttpServerRequest.HttpServerRequest;
      const session = yield* Effect.tryPromise({
        try: () =>
          auth.api.getSession({ headers: new Headers(request.headers) }),
        catch: internalServerError,
      });
      return session;
    });

    const requireUser = Effect.fn("Auth.requireUser")(function* () {
      const session = yield* getSession();
      if (!session) {
        return yield* new HttpApiError.Unauthorized({});
      }
      return {
        id: session.user.id,
        name: session.user.name,
        email: session.user.email,
      };
    });

    return { getSession, requireUser };
  }),
}) {
  static readonly layer = Layer.effect(this, this.make);
}

import { Context, Effect, Layer, Schema } from "effect";
import { HttpApiMiddleware } from "effect/unstable/httpapi";

import { Auth } from "@/services/auth";

export class CurrentUser extends Context.Service<
  CurrentUser,
  {
    id: string;
    name: string;
    email: string;
  }
>()("site/CurrentUser") {}

export class Unauthorized extends Schema.TaggedErrorClass<Unauthorized>()(
  "Unauthorized",
  {
    message: Schema.String,
  },
  { httpApiStatus: 401 },
) {}

export class AuthMiddleware extends HttpApiMiddleware.Service<
  AuthMiddleware,
  {
    provides: CurrentUser;
  }
>()("site/AuthMiddleware", {
  error: Unauthorized,
}) {}

export const AuthMiddlewareLive = Layer.effect(
  AuthMiddleware,
  Effect.gen(function* () {
    const authService = yield* Auth;
    return (httpEffect) =>
      Effect.gen(function* () {
        const user = yield* authService
          .requireUser()
          .pipe(
            Effect.mapError(
              () => new Unauthorized({ message: "Authentication required" }),
            ),
          );
        return yield* Effect.provideService(httpEffect, CurrentUser, user);
      });
  }),
).pipe(Layer.provide(Auth.layer));

